import marshal, dis, types
data=open('/tmp/pyi_out/check_proof','rb').read()
code=marshal.loads(data)
def find(c, name):
    for const in c.co_consts:
        if isinstance(const, types.CodeType):
            if const.co_name==name: return const
            r=find(const,name)
            if r: return r
    return None
