print("ARGS", fn.co_varnames[:fn.co_argcount])
print("CONSTS:")
for c in fn.co_consts:
    if not isinstance(c,types.CodeType): print("   ",repr(c)[:140])
print("NAMES:", fn.co_names)
dis.dis(fn)
